// Initialize the automation system
const { exec } = require('child_process');
const path = require('path');
const fs = require('fs');

// Set up environment variables
process.env.NEWSAPI_KEY = process.env.NEWSAPI_KEY || $vars.NEWSAPI_KEY;
process.env.OPENROUTER_API_KEY = process.env.OPENROUTER_API_KEY || $vars.OPENROUTER_API_KEY;
process.env.FB_PAGE_ACCESS_TOKEN = process.env.FB_PAGE_ACCESS_TOKEN || $vars.FB_PAGE_ACCESS_TOKEN;
process.env.FB_PAGE_ID = process.env.FB_PAGE_ID || $vars.FB_PAGE_ID;
process.env.STORAGE_DIR = process.env.STORAGE_DIR || '/tmp/storage';
process.env.OUTPUT_DIR = process.env.OUTPUT_DIR || '/tmp/output';
process.env.LOG_DIR = process.env.LOG_DIR || '/tmp/logs';

// Create necessary directories
[process.env.STORAGE_DIR, process.env.OUTPUT_DIR, process.env.LOG_DIR].forEach(dir => {
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
});

return [{ json: { message: 'Environment prepared', timestamp: new Date().toISOString() } }];

const { exec } = require('child_process');
const util = require('util');
const execPromise = util.promisify(exec);

const pythonScript = process.env.PYTHON_SCRIPT_PATH || '/app/scripts/main.py';

try {
  // Run the Python automation script
  const { stdout, stderr } = await execPromise(`python3 ${pythonScript}`);

  // Parse the JSON output from the script
  let results;
  const jsonMatch = stdout.match(/AUTOMATION RESULTS:[\s\S]*/);
  if (jsonMatch) {
    results = JSON.parse(jsonMatch[0].replace('AUTOMATION RESULTS:', '').trim());
  } else {
    results = {
      success: true,
      message: stdout,
      errors: stderr ? [stderr] : []
    };
  }

  return [{ json: results }];
} catch (error) {
  return [{ 
    json: { 
      success: false, 
      error: error.message,
      timestamp: new Date().toISOString()
    } 
  }];
}

// Log successful results
const results = $input.first().json;

console.log('Automation cycle completed successfully!');
console.log(`Trends found: ${results.trends_found || 0}`);
console.log(`Posts created: ${results.posts_created || 0}`);
console.log(`Facebook posts: ${results.facebook_posts || 0}`);

if (results.posts && results.posts.length > 0) {
  results.posts.forEach((post, index) => {
    console.log(`\nPost ${index + 1}:`);
    console.log(`  Topic: ${post.topic}`);
    console.log(`  Headline: ${post.headline}`);
    console.log(`  Image: ${post.image_path}`);
    if (post.facebook_post_id) {
      console.log(`  FB Post ID: ${post.facebook_post_id}`);
    }
  });
}

return [{ json: { 
  status: 'success', 
  message: 'Automation completed successfully',
  ...results 
}}];

// Log error details
const errorData = $input.first().json;

console.error('Automation cycle completed with errors!');
console.error(`Errors: ${JSON.stringify(errorData.errors, null, 2)}`);

// Format error message for notification
const errorMessage = errorData.errors.join('\n');

return [{ json: { 
  status: 'error', 
  message: 'Automation completed with errors',
  errors: errorData.errors,
  errorSummary: errorMessage
}}];

// Prepare summary for notification
const data = $input.first().json;

const summary = {
  timestamp: new Date().toISOString(),
  status: data.status,
  trendsFound: data.trends_found || 0,
  postsCreated: data.posts_created || 0,
  facebookPosts: data.facebook_posts || 0,
  errors: data.errors || [],
  posts: data.posts || []
};

return [{ json: summary }];
